/**
 * ADMIN PAGES - Functional Tests
 * Test các admin pages với functional checks
 */
test.describe('Admin Pages - Functional Coverage', () => {
  const ADMIN_PAGES = [
    { path: '/admin/features-demo.html', name: 'Features Demo', expectedElements: ['feature', 'demo', 'component'] },
    { path: '/admin/features-demo-2027.html', name: 'Features Demo 2027', expectedElements: ['feature', 'demo', '2027'] },
    { path: '/admin/components-demo.html', name: 'Components Demo', expectedElements: ['component', 'ui', 'button'] },
    { path: '/admin/ui-components-demo.html', name: 'UI Components Demo', expectedElements: ['ui', 'component', 'demo'] },
    { path: '/admin/ux-components-demo.html', name: 'UX Components Demo', expectedElements: ['ux', 'component', 'interaction'] },
    { path: '/admin/ui-demo.html', name: 'UI Demo', expectedElements: ['ui', 'demo', 'interface'] },
    { path: '/admin/quality.html', name: 'Quality Control', expectedElements: ['quality', 'control', 'check'] },
    { path: '/admin/notifications.html', name: 'Admin Notifications', expectedElements: ['notification', 'alert', 'message'] },
    { path: '/admin/inventory.html', name: 'Inventory', expectedElements: ['inventory', 'stock', 'product'] },
    { path: '/admin/agents.html', name: 'AI Agents', expectedElements: ['agent', 'ai', 'automation'] },
  ];

  for (const page of ADMIN_PAGES) {
    test.describe(`${page.name}`, () => {
      test('loads without critical errors', async ({ page: p }) => {
        const errors: string[] = [];
        p.on('pageerror', (error) => {
          // Ignore expected errors ( Supabase config, env vars not loaded in test)
          if (error.message.includes('supabase') || error.message.includes('__ENV__')) return;
          if (/is not defined/.test(error.message) && /createDemo|Auth|mekongAgents/.test(error.message)) return;
          if (error.message.includes('CustomElementRegistry')) return;
          errors.push(error.message);
        });

        const response = await p.goto(page.path, { waitUntil: 'commit', timeout: 30000 });
        expect(response?.status()).toBe(200);
        // Allow up to 3 non-critical errors
        expect(errors.length).toBeLessThanOrEqual(3);
      });

      test('has valid HTML structure', async ({ page: p }) => {
        await p.goto(page.path, { waitUntil: 'commit', timeout: 30000 });

        // Check DOCTYPE
        const hasDoctype = await p.evaluate(() => document.firstChild?.nodeType === 10);
        expect(hasDoctype).toBe(true);

        // Check html lang
        const htmlLang = await p.getAttribute('html', 'lang');
        expect(htmlLang).toBeTruthy();

        // Check title
        const title = await p.title();
        expect(title.length).toBeGreaterThan(0);
      });

      test('has required meta tags', async ({ page: p }) => {
        await p.goto(page.path, { waitUntil: 'commit', timeout: 30000 });

        // Viewport
        const viewport = await p.getAttribute('meta[name="viewport"]', 'content');
        expect(viewport).toBeTruthy();

        // Charset
        const charset = await p.querySelector('meta[charset]');
        expect(charset).toBeTruthy();
      });
    });
  }
});

/**
 * FEATURES DEMO - Specific Tests
 */
test.describe('Features Demo Pages', () => {
  test('features-demo loads with widgets', async ({ page }) => {
    const response = await page.goto('/admin/features-demo.html', {
      waitUntil: 'domcontentloaded',
      timeout: 10000
    });
    expect(response?.status()).toBe(200);

    // Check for widget containers
    const widgetCount = await page.locator('[class*="widget"], [data-widget]').count();
    expect(widgetCount).toBeGreaterThan(0);
  });

  test('features-demo-2027 has advanced features', async ({ page }) => {
    await page.goto('/admin/features-demo-2027.html', { waitUntil: 'domcontentloaded' });

    // Check for 2027-specific features
    const hasAdvancedFeatures = await page.locator('[class*="advanced"], [class*="ai-"], [class*="smart-"]').count();
    expect(hasAdvancedFeatures).toBeGreaterThan(0);
  });

  test('components-demo has UI components', async ({ page }) => {
    await page.goto('/admin/components-demo.html', { waitUntil: 'domcontentloaded' });

    // Check for component examples
    const hasButtons = await page.locator('button').count();
    const hasInputs = await page.locator('input').count();
    const hasCards = await page.locator('[class*="card"]').count();

    expect(hasButtons + hasInputs + hasCards).toBeGreaterThan(0);
  });
});

