/**
 * PERFORMANCE - Load Time Tests
 */
test.describe('Admin Performance', () => {
  const PAGES = [
    '/admin/features-demo.html',
    '/admin/components-demo.html',
    '/admin/inventory.html',
  ];

  for (const pagePath of PAGES) {
    test(`${pagePath} loads within 3 seconds`, async ({ page }) => {
      const startTime = Date.now();
      const response = await page.goto(pagePath, { waitUntil: 'domcontentloaded', timeout: 10000 });
      const loadTime = Date.now() - startTime;

      expect(response?.status()).toBe(200);
      expect(loadTime).toBeLessThan(3000); // 3 second threshold
    });
  }
});
